core:effect.signature:
export const effect = (fn: () => void): SignalsEffect => {
  const signalsEffect = fn as SignalsEffect;
  signalsEffect.canDisposeNow = false;
  signalsEffect.dispose = () => {
    signalsEffect.canDisposeNow = true;
  };

  setCurrentEffect(signalsEffect);
  fn();
  setCurrentEffect(null);

  return signalsEffect;
};

examples:
```typescript
const count = signal(0);

// Simple effect
effect(() => {
  console.log("Count is:", count.value);
});

// Multiple signal tracking
const name = signal("John");
const age = signal(30);
effect(() => {
  console.log(`${name.value} is ${age.value} years old`);
});

// Disposal
const eff = effect(() => {
  console.log(count.value);
});
eff.dispose();
count.value = 5; // Effect won't run
```

core:dispose.signature:
export const dispose = (
  ...derivedSignalsOrEffects: (DerivedSignal<any> | SignalsEffect)[]
): void => {
  derivedSignalsOrEffects.forEach((dsigOrEff) => dsigOrEff.dispose());
};

examples:
```typescript
const count = signal(0);
const doubled = derive(() => count.value * 2);
const eff = effect(() => console.log(count.value));

// Dispose single
dispose(doubled);

// Dispose multiple
dispose(doubled, eff);

// Mixed disposal
dispose(doubled, eff);

// Empty (no-op)
dispose();
```

