core:derive.signature:
export const derive = <T>(
  valueGetterFn: DerivedValueGetterWithSignals<T>,
): DerivedSignal<T> => {
  let oldValue: T | undefined;
  let currValue: T | undefined;
  const derivedSource = signal<T>(oldValue as T);
  const derivedSourceUpdator = effect(() => {
    oldValue = currValue;
    currValue = valueGetterFn(oldValue);
    derivedSource.value = currValue;
  });

  const baseDerivedSignal: BaseDerivedSignal<T> = {
    type: "derived-signal" as const,
    get prevValue() {
      return oldValue;
    },
    get value() {
      return derivedSource.value as T;
    },
    dispose() {
      derivedSourceUpdator.dispose();
    },
  };

  // Add non-mutating methods for array, string, number, and boolean derived signals
  if (Array.isArray(derivedSource.value)) {
    return Object.assign(
      baseDerivedSignal,
      getArraySignalNonMutatingMethodsObject(
        baseDerivedSignal as BaseDerivedSignal<any[]>,
      ),
    ) as any;
  }

  if (isPlainObject(derivedSource.value)) {
    return Object.assign(
      baseDerivedSignal,
      getObjectSignalNonMutatingMethodsObject(
        baseDerivedSignal as BaseDerivedSignal<Record<string, any>>,
      ),
    ) as any;
  }

  if (typeof derivedSource.value === "string") {
    return Object.assign(
      baseDerivedSignal,
      getStringSignalMethodsObject(
        baseDerivedSignal as BaseDerivedSignal<string>,
      ),
    ) as any;
  }

  if (typeof derivedSource.value === "number") {
    return Object.assign(
      baseDerivedSignal,
      getNumberSignalMethodsObject(
        baseDerivedSignal as BaseDerivedSignal<number>,
      ),
    ) as any;
  }

  if (typeof derivedSource.value === "boolean") {
    return Object.assign(
      baseDerivedSignal,
      getBooleanSignalNonMutatingMethodsObject(
        baseDerivedSignal as BaseDerivedSignal<boolean>,
      ),
    ) as any;
  }

  return baseDerivedSignal as any;
};

examples:
```typescript
const count = signal(5);
const doubled = derive(() => count.value * 2);
console.log(doubled.value); // 10

// Using previous value
const history = derive((prev) => {
  const current = count.value;
  return prev ? [...prev, current] : [current];
});
```

