      }),
    andThisIsGTE: (
      subjectValue: MaybeSignalValue<number>,
      compareValue: MaybeSignalValue<number>
    ) =>
      genericOp(() => {
        const val = evaluator();
        const comparisonResult = value(subjectValue) >= value(compareValue);
        return !!(val && comparisonResult);
      }),
  };
};

