};

api:op.signature:
export const op = <T>(input: MaybeSignalValue<T> | (() => T)): Operation<T> => {
  const evaluator: () => T =
    typeof input === "function"
      ? (input as () => T)
      : (): T => value(input as MaybeSignalValue<T>);
  const val = evaluator();

  return (
    typeof val === "number"
      ? numberOp(input as MaybeSignalValue<number> | (() => number))
      : typeof val === "string" || Array.isArray(val)
      ? stringAndArrayOp(
          input as
            | MaybeSignalValue<string | unknown[]>
            | (() => string | unknown[])
        )
      : genericOp(input)
  ) as Operation<T>;
};

examples:
```typescript
const count = signal(5);
const operation = op(count);
const doubled = operation.add(5).result; // DerivedSignal<number>

const text = signal("hello");
const textOp = op(text);
const isLong = textOp.lengthGT(5).truthy; // DerivedSignal<boolean>

const value = signal(10);
const check = op(value).isBetween(5, 15).truthy; // DerivedSignal<boolean>
```

api:receive.signature:
export const receive = <T>(
  receiver: SourceSignal<T>,
  ...transmittors: Signal<T>[]
): SignalsEffect[] => {
  const effects = transmittors.map((transmittor) =>
    effect(() => (receiver.value = transmittor.value))
  );
  return effects;
};

examples:
```typescript
const sportsEvent = signal("cricket @ 9am");
const mediaEvent = signal("movie @ 3pm");
const noticeBoard = signal("");

const effects = receive(noticeBoard, sportsEvent, mediaEvent);

sportsEvent.value = "football @ 1pm";
console.log(noticeBoard.value); // "football @ 1pm"

mediaEvent.value = "concert @ 8pm";
console.log(noticeBoard.value); // "concert @ 8pm"

// Manual update still works
noticeBoard.value = "No events";

// Dispose connections
effects.forEach(eff => eff.dispose());
```

